const c={"Sun-Aries":{core:"You lead with fire and instinct, moving through the world like someone who was born knowing how to begin things. There is a raw courage in your identity that others find both inspiring and intimidating. You are at your best when you have something to fight for.",strengths:["Natural initiative and courage","Infectious enthusiasm","Fearless authenticity"],blindSpots:["Impatience with slower-moving people","Mistaking aggression for assertiveness"],underStress:["Becomes combative and picks fights to discharge tension","Burns out from refusing to slow down or ask for help"],growthPath:["Learning to channel fire into sustained purpose rather than reactive impulse","Developing patience as a form of strength rather than submission"]},"Sun-Taurus":{core:"Your identity is rooted in what endures. You build your life slowly and deliberately, trusting the body and the senses over abstract ideas. There is a deep steadiness in you that becomes an anchor for everyone around you.",strengths:["Remarkable patience and persistence","Strong aesthetic sensibility","Grounded reliability"],blindSpots:["Stubbornness disguised as consistency","Resisting change long past its due date"],underStress:["Digs in with immovable stubbornness and shuts down emotionally","Seeks comfort through excess as a way to self-soothe"],growthPath:["Embracing change as a natural extension of growth rather than a threat","Learning that letting go can be its own form of abundance"]},"Sun-Gemini":{core:"Your mind is a living, restless thing that needs constant stimulation and variety. You understand the world by naming it, questioning it, and then questioning your own answers. People are drawn to your wit, but few realize how deeply you actually think.",strengths:["Quick adaptability","Gift for communication and connection","Intellectual curiosity that never fades"],blindSpots:["Scattered energy across too many interests","Using humor to deflect from vulnerability"],underStress:["Becomes scattered and anxious, spinning between tasks without landing","Over-intellectualizes pain to avoid sitting with difficult feelings"],growthPath:["Committing deeply to one path while honoring the need for variety","Allowing silence and stillness to become sources of insight"]},"Sun-Cancer":{core:"You feel the world before you think about it, and your emotional intelligence is your greatest compass. Home, family, and belonging are not just preferences but core needs woven into your identity. Your sensitivity is not weakness; it is your superpower.",strengths:["Profound emotional intuition","Fierce protectiveness of loved ones","Ability to create safety anywhere"],blindSpots:["Taking things personally that are not about you","Retreating into your shell instead of communicating"],underStress:["Withdraws into protective isolation and refuses to let anyone in","Becomes emotionally reactive, interpreting everything as a personal attack"],growthPath:["Building inner security that does not depend on external validation","Learning to nurture yourself with the same devotion you offer others"]},"Sun-Leo":{core:"You were born to shine, and when you dim your light to make others comfortable, everyone loses. Your warmth is genuine, your generosity is instinctive, and your need to be seen is not vanity but a deep desire to share your gifts with the world.",strengths:["Magnetic presence and warmth","Creative self-expression","Generous spirit that uplifts others"],blindSpots:["Needing external validation to feel worthy","Struggling when not in the spotlight"],underStress:["Becomes domineering and demands recognition to soothe wounded pride","Dramatizes situations to reclaim attention and a sense of importance"],growthPath:["Cultivating an inner flame of worth that no audience can extinguish","Using your radiance to illuminate others rather than outshine them"]},"Sun-Virgo":{core:"You notice what others miss, and this gift for discernment shapes everything about how you move through the world. Your desire to improve things comes from genuine care, not criticism. You are quietly one of the most devoted people in any room.",strengths:["Extraordinary attention to detail","Humble dedication to service","Practical problem-solving ability"],blindSpots:["Perfectionism that leads to paralysis","Being harder on yourself than anyone else"],underStress:["Spirals into obsessive self-criticism and fixates on minor flaws","Over-works and micromanages as a way to regain a sense of control"],growthPath:["Accepting imperfection as part of wholeness rather than failure","Directing your gift for improvement inward with compassion instead of judgment"]},"Sun-Libra":{core:"You experience yourself most fully through your relationships and the art of creating harmony. Beauty, fairness, and balance are not superficial concerns for you but genuine guiding principles. You have a rare ability to see every side of a situation.",strengths:["Natural diplomacy and grace","Deep appreciation for beauty and art","Gift for making others feel valued"],blindSpots:["Indecisiveness from seeing all perspectives","Losing yourself in the desire to please"],underStress:["Becomes paralyzed by indecision and defers to others to avoid blame","People-pleases compulsively, abandoning personal needs for false peace"],growthPath:["Making decisive choices that honor your own values, not just consensus","Discovering that authentic harmony includes your own voice at full volume"]},"Sun-Scorpio":{core:"You live at a depth that most people are afraid to visit. Truth is your currency, and you would rather face something painful than live with a comfortable lie. Your intensity is not something to tone down; it is the engine of your transformation.",strengths:["Unflinching emotional honesty","Powerful capacity for transformation","Fierce loyalty to those you trust"],blindSpots:["Holding onto resentment as a form of control","Testing people before trusting them"],underStress:["Retreats into suspicion and emotional withdrawal as self-protection","Fixates on perceived betrayals and plots retaliation internally"],growthPath:["Releasing the need to control outcomes through sheer emotional will","Trusting that vulnerability with the right people is power, not exposure"]},"Sun-Sagittarius":{core:"Your spirit is fundamentally oriented toward expansion, adventure, and meaning. You need to feel that life is going somewhere, that there is always a new horizon to chase. Your optimism is contagious, and your honesty, while sometimes blunt, is always refreshing.",strengths:["Boundless optimism and enthusiasm","Natural philosophical insight","Ability to inspire others to dream bigger"],blindSpots:["Restlessness that avoids commitment","Bluntness that lands as tactlessness"],underStress:["Flees into escapism or over-schedules adventures to avoid pain","Becomes preachy and self-righteous, insisting their worldview is the only valid one"],growthPath:["Finding the adventure in stillness and the freedom within commitment","Tempering honesty with empathy so truth lands as medicine, not a blow"]},"Sun-Capricorn":{core:"You understand that meaningful things take time, and you are willing to do the work that others are not. There is an old soul quality to you, a quiet authority that has been there since childhood. You earn your place in the world, and you know it.",strengths:["Disciplined ambition","Quiet resilience under pressure","Strategic long-term vision"],blindSpots:["Equating your worth with your achievements","Difficulty letting yourself rest or play"],underStress:["Doubles down on work and isolates, believing no one else can carry the load","Becomes rigidly controlling, confusing pessimism with realism"],growthPath:["Learning that rest and play are not earned but inherently deserved","Allowing yourself to be supported without interpreting it as weakness"]},"Sun-Aquarius":{core:"You see the world not as it is but as it could be, and this visionary quality sets you apart from the crowd even when you desperately want to belong to it. Your independence is not aloofness; it is the price of thinking differently.",strengths:["Original and progressive thinking","Deep commitment to fairness","Ability to befriend anyone"],blindSpots:["Intellectualizing emotions instead of feeling them","Detaching when things get too intimate"],underStress:["Detaches completely and retreats into the mind to avoid emotional overwhelm","Becomes contrarian and cold, pushing away the very connections they need"],growthPath:["Bridging the gap between humanitarian ideals and personal emotional intimacy","Allowing yourself to need specific people, not just humanity at large"]},"Sun-Pisces":{core:"You absorb the world like a sponge, feeling the joy and pain of everyone around you as if it were your own. Your imagination is vast and your compassion is boundless, but you need to learn that you cannot save everyone without first saving yourself.",strengths:["Extraordinary empathy and compassion","Rich creative imagination","Spiritual depth and intuition"],blindSpots:["Difficulty maintaining boundaries","Escapism when reality becomes overwhelming"],underStress:["Dissolves into overwhelm and numbs out through escapist behaviors","Absorbs everyone else s pain and loses track of their own identity"],growthPath:["Building firm boundaries as an act of self-love rather than selfishness","Channeling boundless compassion into disciplined creative or healing practice"]},"Moon-Aries":{core:"Your emotional world moves fast. You feel things intensely and immediately, and you need to act on your feelings to process them. Sitting with difficult emotions is your biggest challenge, but your emotional courage is unmatched.",strengths:["Quick emotional recovery","Brave in expressing feelings","Instinctive protectiveness"],blindSpots:["Reacting before fully understanding what you feel","Impatience with emotional complexity"],underStress:["Lashes out impulsively and regrets it almost immediately","Converts vulnerability into anger because anger feels more manageable"],growthPath:["Developing the courage to sit with discomfort instead of charging through it","Recognizing that emotional patience is its own form of bravery"]},"Moon-Taurus":{core:"Emotional security is everything to you, and you find it through comfort, routine, and physical presence. You process feelings slowly and deeply, like roots growing underground. Once you feel safe, you are the most nurturing presence imaginable.",strengths:["Deeply calming presence","Emotional steadfastness","Ability to create comfort and warmth"],blindSpots:["Emotional resistance to necessary change","Comfort-seeking as avoidance"],underStress:["Shuts down emotionally and clings to familiar routines as a lifeline","Becomes possessive of people and spaces that represent security"],growthPath:["Trusting that emotional safety can travel with you through change","Allowing feelings to move and shift without losing your ground"]},"Moon-Gemini":{core:"You process emotions by talking about them, thinking about them, and sometimes by talking about thinking about them. Your emotional life is linked to your mental life in a way that can be both a gift and a complication. You need variety in how you nurture yourself.",strengths:["Emotional versatility and adaptability","Ability to articulate complex feelings","Lightness that helps others through heavy moments"],blindSpots:["Rationalizing feelings instead of truly feeling them","Emotional restlessness and inconsistency"],underStress:["Talks nervously and circles around feelings without ever landing in the body","Splits attention in a dozen directions to avoid the weight of any single emotion"],growthPath:["Learning to let feelings exist without needing to narrate or explain them","Discovering that emotional depth and intellectual agility can coexist"]},"Moon-Cancer":{core:"Your emotional world is your homeland, and you navigate it with a fluency that others can barely comprehend. You feel the moods of a room the moment you walk in, and you carry the emotional history of your family in your bones.",strengths:["Profound emotional intelligence","Natural nurturing instinct","Deep memory and sentimental loyalty"],blindSpots:["Moodiness that confuses those around you","Clinging to emotional patterns from childhood"],underStress:["Retreats into nostalgic longing and withdraws from present relationships","Becomes emotionally flooded and projects old wounds onto current situations"],growthPath:["Distinguishing inherited emotional patterns from your own authentic feelings","Nurturing yourself as tenderly as you nurture everyone else"]},"Moon-Leo":{core:"You need to feel special, admired, and emotionally celebrated, and there is nothing wrong with that. Your emotional generosity is enormous; you love with your whole chest. When you feel appreciated, you become the warmest light in the room.",strengths:["Warm and generous emotional expression","Loyalty that never wavers","Ability to make others feel like royalty"],blindSpots:["Taking emotional slights very personally","Needing constant reassurance of love"],underStress:["Becomes theatrically wounded and demands emotional center stage","Withdraws warmth as punishment when feeling overlooked or unappreciated"],growthPath:["Generating self-worth from within rather than from applause","Offering love freely without keeping a ledger of what comes back"]},"Moon-Virgo":{core:"You show love through acts of service and quiet attentiveness. Your emotional world is organized around being useful, and you process feelings by analyzing them carefully. You care deeply but often struggle to let yourself receive the same care you give.",strengths:["Thoughtful emotional support","Calm under emotional pressure","Devotion expressed through daily acts"],blindSpots:["Self-criticism when emotions feel messy","Difficulty accepting care from others"],underStress:["Becomes hyper-critical of themselves and everyone around them","Channels anxiety into compulsive fixing, cleaning, or organizing"],growthPath:["Allowing emotions to be imperfect and still worthy of expression","Receiving care from others as gracefully as you give it"]},"Moon-Libra":{core:"Harmony in your relationships is not a luxury; it is an emotional need. You feel most at peace when the people around you are at peace, which can lead you to absorb conflict that is not yours to carry. Your emotional grace is genuine and rare.",strengths:["Emotional diplomacy and fairness","Ability to see both sides in conflicts","Creating beauty as emotional nourishment"],blindSpots:["Suppressing your own needs for harmony","Codependency disguised as love"],underStress:["Appeases everyone at the cost of their own emotional truth","Becomes passive-aggressive when direct expression feels too disruptive"],growthPath:["Honoring your own emotional needs as equal to those of others","Learning that genuine peace sometimes requires honest disruption"]},"Moon-Scorpio":{core:"Your feelings run deeper than most people will ever understand. You experience emotions as transformative forces, and you are not interested in surface-level connections. Trust is sacred to you, and betrayal is the one wound you carry longest.",strengths:["Emotional depth and fearlessness","Powerful instincts about people","Capacity for total emotional commitment"],blindSpots:["Jealousy and possessiveness in love","Difficulty letting go of past emotional wounds"],underStress:["Becomes intensely suspicious and reads betrayal into innocent gestures","Shuts down completely and weaponizes silence as emotional control"],growthPath:["Transforming old wounds into wisdom rather than armor","Choosing trust as a conscious act of power rather than a surrender"]},"Moon-Sagittarius":{core:"You need emotional freedom the way others need security. Your feelings are big, expansive, and optimistic, and you process them best through movement, travel, and laughter. You heal by seeking meaning in your pain rather than dwelling in it.",strengths:["Emotional resilience and optimism","Ability to find humor in difficult times","Generous and open-hearted spirit"],blindSpots:["Running from heavy emotions","Dismissing others feelings as overreactions"],underStress:["Bolts emotionally or physically when feelings become too confining","Masks pain with forced optimism and refuses to acknowledge grief"],growthPath:["Staying present with heavy emotions instead of seeking the nearest exit","Discovering that depth of feeling expands your world as much as travel does"]},"Moon-Capricorn":{core:"You learned early that emotions must be managed, and this has given you a remarkable composure that others admire and sometimes misread as coldness. Underneath that composed exterior lives a deeply feeling person who simply needs to feel safe before opening up.",strengths:["Emotional maturity beyond your years","Reliability in crisis","Quiet depth of feeling"],blindSpots:["Suppressing emotions until they erupt","Equating vulnerability with weakness"],underStress:["Walls off all emotion and becomes coldly functional to survive","Turns inward with harsh self-judgment, believing they should be handling it better"],growthPath:["Allowing yourself to fall apart occasionally without seeing it as failure","Recognizing that emotional openness is a form of strength, not liability"]},"Moon-Aquarius":{core:"You process feelings through the lens of ideas and ideals, which gives you a unique emotional perspective but can also distance you from the raw experience of feeling. You care deeply about humanity while sometimes struggling with personal intimacy.",strengths:["Emotional objectivity in crisis","Compassion for collective suffering","Freedom-respecting approach to love"],blindSpots:["Intellectualizing emotions to avoid pain","Feeling alien in emotionally intense situations"],underStress:["Dissociates from feelings and retreats into detached observation","Dismisses personal emotional needs as irrational or unimportant"],growthPath:["Letting yourself feel messy, irrational emotions without analyzing them away","Bridging the gap between caring for the collective and being present for one person"]},"Moon-Pisces":{core:"Your emotional boundaries are thin, and you absorb the feelings of everyone around you like a psychic sponge. This makes you extraordinarily compassionate but also vulnerable to emotional overwhelm. You need solitude and creative outlets to process what you carry.",strengths:["Boundless empathy and compassion","Rich inner emotional world","Healing presence for others"],blindSpots:["Difficulty distinguishing your feelings from others","Emotional escapism through fantasy or substances"],underStress:["Becomes emotionally porous and loses all sense of where they end and others begin","Retreats into fantasy, sleep, or numbing to escape the weight of feeling everything"],growthPath:["Developing discernment about which emotions are yours to carry","Grounding your vast emotional world through consistent creative or spiritual practice"]},"Rising-Aries":{core:"You enter every room like you have somewhere important to be. Your first instinct is to act, to move, to lead, and people immediately sense your directness. Life keeps asking you to be brave, and you keep saying yes.",strengths:["Commanding first impression","Quick to take initiative","Energizing presence"],blindSpots:["Coming on too strong in new situations","Impatience with social pleasantries"],underStress:["Becomes abrupt and confrontational, alienating the allies they need most","Charges ahead recklessly, mistaking speed for progress"],growthPath:["Tempering bold first instincts with a moment of strategic pause","Learning that how you arrive matters as much as the fact that you showed up"]},"Rising-Taurus":{core:"You move through the world with a calm, grounded steadiness that puts others at ease immediately. People sense your reliability before you even speak. Life keeps bringing you lessons about what truly holds value and what is just noise.",strengths:["Naturally calming presence","Approachable and trustworthy demeanor","Strong sense of personal style"],blindSpots:["Appearing resistant to new ideas","Slowness to adapt to new environments"],underStress:["Becomes immovable and refuses to engage with anything unfamiliar","Retreats into material comfort and sensory indulgence to avoid confrontation"],growthPath:["Welcoming new experiences as enrichments to your stable foundation","Letting your calm presence be a bridge rather than a wall"]},"Rising-Gemini":{core:"You are perpetually curious, and people sense your quick mind and versatile energy immediately upon meeting you. You adapt to social situations like water adapting to its container. Life keeps teaching you that depth and breadth can coexist.",strengths:["Witty and engaging first impression","Social adaptability","Youthful energy at any age"],blindSpots:["Appearing scattered or unreliable","Nervousness that masks itself as chattiness"],underStress:["Talks faster and listens less, filling every silence with nervous energy","Shapeshifts so rapidly between personas that they lose track of their authentic self"],growthPath:["Grounding your versatility in a consistent sense of identity","Allowing curiosity to deepen into expertise without losing your playfulness"]},"Rising-Cancer":{core:"People sense your warmth and sensitivity from the first moment. You approach the world with your guard subtly up, testing the emotional waters before fully arriving. Life keeps teaching you that vulnerability is the doorway to the belonging you seek.",strengths:["Warm and approachable energy","Intuitive read on new people","Naturally nurturing presence"],blindSpots:["Withdrawing at the first sign of emotional risk","Resting face that reveals every mood"],underStress:["Pulls inward and builds walls, becoming unapproachable despite craving connection","Projects emotional needs onto others and becomes overly caretaking"],growthPath:["Stepping into new environments with open trust instead of preemptive defense","Showing the world your full self before you know it is completely safe"]},"Rising-Leo":{core:"You walk into a room and the room notices. There is a natural radiance to your presence that draws attention whether you seek it or not. Life keeps inviting you to step into your full self-expression without apology.",strengths:["Magnetic and confident presence","Natural ability to command attention","Warmth that puts people at ease"],blindSpots:["Overidentifying with how others perceive you","Struggling when you do not receive immediate recognition"],underStress:["Becomes performatively confident to mask deep insecurity","Demands the spotlight and reacts dramatically when it shifts away"],growthPath:["Letting your presence speak without needing to manage how it is received","Finding joy in elevating others into the light alongside you"]},"Rising-Virgo":{core:"You meet the world with a quiet, observant intelligence that takes everything in before responding. People sense your competence and your modesty simultaneously. Life keeps asking you to trust that you are enough exactly as you are.",strengths:["Thoughtful and composed first impression","Keen observational skills","Helpful and approachable energy"],blindSpots:["Coming across as overly critical or reserved","Anxiety that manifests as over-preparation"],underStress:["Becomes rigidly perfectionistic and paralyzed by fear of making a mistake","Over-prepares obsessively, trying to control the uncontrollable"],growthPath:["Approaching the world with curiosity rather than critique","Trusting your innate competence enough to show up without a rehearsal"]},"Rising-Libra":{core:"Grace is your default setting. You approach the world with charm, fairness, and an instinct for beauty that shapes everything from your appearance to your social style. Life keeps teaching you that real harmony includes your own needs.",strengths:["Effortless social grace","Attractive and harmonious presentation","Natural mediation skills"],blindSpots:["People-pleasing as a first response","Indecisiveness about your own path"],underStress:["Agrees with everyone to maintain peace and loses their own position entirely","Becomes superficially pleasant while seething beneath the surface"],growthPath:["Presenting your true opinions even when they disrupt the harmony","Discovering that your grace becomes more magnetic when it includes authenticity"]},"Rising-Scorpio":{core:"You have an intensity that people feel before you say a single word. Your gaze is penetrating, your presence is magnetic, and you do not do anything halfway. Life keeps bringing you into situations that demand transformation and radical honesty.",strengths:["Powerful and memorable presence","Ability to see through pretense","Magnetic intensity"],blindSpots:["Intimidating people unintentionally","Guardedness that keeps connection at arm length"],underStress:["Becomes hyper-vigilant and suspicious, reading threat into neutral encounters","Armors up with intimidating intensity that pushes potential allies away"],growthPath:["Allowing first encounters to unfold without needing to control the dynamic","Softening your gaze enough to let others feel safe approaching you"]},"Rising-Sagittarius":{core:"You bring an infectious optimism and openness to every new encounter. People sense your adventurous spirit and your honesty immediately. Life keeps expanding your horizons and asking you to share what you discover with others.",strengths:["Enthusiastic and open energy","Natural storytelling ability","Approachable warmth and humor"],blindSpots:["Over-promising in the excitement of the moment","Restlessness that reads as disinterest"],underStress:["Over-commits and scatters energy trying to escape through new experiences","Becomes dogmatic and lectures others rather than engaging in real dialogue"],growthPath:["Bringing the same enthusiasm you have for new horizons to present commitments","Learning that your honesty is most powerful when paired with sensitivity"]},"Rising-Capricorn":{core:"You present yourself to the world with a composed, ambitious seriousness that commands respect. People sense your maturity and your quiet determination. Life keeps teaching you that success means nothing if you forget to enjoy the climb.",strengths:["Authoritative and trustworthy presence","Natural leadership energy","Polished self-presentation"],blindSpots:["Appearing cold or unapproachable","Difficulty relaxing in casual settings"],underStress:["Becomes rigidly stoic and refuses to show any sign of struggle","Over-identifies with professional role and loses connection to their personal self"],growthPath:["Letting people see the warmth beneath the composure","Approaching new situations with openness rather than a strategic assessment"]},"Rising-Aquarius":{core:"There is something unmistakably unique about how you present yourself, and people notice it immediately. You approach the world as an observer and a questioner, never quite fitting into any single box. Life keeps asking you to honor your individuality without isolating yourself.",strengths:["Intriguingly unique presence","Open-minded approach to everyone","Progressive and forward-thinking energy"],blindSpots:["Emotional detachment in first impressions","Rebelliousness for its own sake"],underStress:["Withdraws into aloof detachment and dismisses social expectations entirely","Doubles down on being different as a defense against feeling unseen"],growthPath:["Connecting your individuality to community rather than using it as a barrier","Allowing yourself to be ordinary in some moments without feeling diminished"]},"Rising-Pisces":{core:"You meet the world with a soft, dreamy openness that makes people feel instantly seen and accepted. There is something ethereal about your presence, as if you are tuned into a frequency most people cannot hear. Life keeps teaching you how to stay grounded while remaining open.",strengths:["Gentle and empathetic presence","Artistic and imaginative first impression","Ability to make anyone feel safe"],blindSpots:["Absorbing the energy of every environment","Appearing vague or unfocused"],underStress:["Becomes unmoored and dissociates from practical reality","Absorbs the chaos of their environment and loses their center completely"],growthPath:["Developing grounding practices that anchor your openness in the body","Learning to be present without merging with everything around you"]},"Mercury-Aries":{core:"Your mind works at lightning speed, and your thoughts come out before you have time to edit them. You think in bold strokes rather than fine details, and your communication style is refreshingly direct. You are at your sharpest in debates and brainstorms.",strengths:["Quick decisive thinking","Bold communication style","Ability to cut through overthinking"],blindSpots:["Speaking before fully thinking","Dismissing ideas that take time to develop"],underStress:["Becomes verbally aggressive and cuts people off mid-sentence","Makes snap decisions fueled by adrenaline rather than clarity"],growthPath:["Pausing long enough to let a thought fully form before voicing it","Recognizing that listening is as powerful a communication tool as speaking"]},"Mercury-Taurus":{core:"You think slowly and deliberately, and your ideas are all the more solid for it. Your mind gravitates toward practical, tangible solutions, and you have a gift for making complex things simple. Once you have formed an opinion, it takes a lot to change it.",strengths:["Grounded and practical thinking","Clear and steady communication","Excellent follow-through on ideas"],blindSpots:["Mental stubbornness","Slowness to adapt to new information"],underStress:["Refuses to consider alternative viewpoints and entrenches in old thinking","Goes mentally silent and stonewalls rather than engaging with difficult topics"],growthPath:["Allowing new information to reshape your views without threatening your foundation","Trusting that thoughtful flexibility strengthens rather than weakens your ideas"]},"Mercury-Gemini":{core:"Your mind is a perpetual motion machine, endlessly curious, constantly making connections between seemingly unrelated ideas. You learn by talking, asking, and exploring, and you communicate with a sparkle that keeps people engaged. Information is your playground.",strengths:["Brilliant conversationalist","Rapid information processing","Versatile and curious mind"],blindSpots:["Superficial knowledge across too many subjects","Difficulty focusing on one topic deeply"],underStress:["Becomes mentally frantic, jumping between topics without completing any thought","Fills anxious silence with compulsive talking and information overload"],growthPath:["Channeling mental brilliance into sustained depth on chosen subjects","Discovering that focused attention reveals more than rapid scanning ever could"]},"Mercury-Cancer":{core:"You think with your feelings, and your memory is tied to emotion in a way that makes your recall vivid and personal. Your communication style is intuitive and nurturing, and you have a gift for saying exactly what someone needs to hear in a difficult moment.",strengths:["Emotionally intelligent communication","Strong emotional memory","Intuitive understanding of subtext"],blindSpots:["Thinking clouded by mood swings","Difficulty being objective in emotional situations"],underStress:["Thoughts spiral into worst-case scenarios colored by fear and old memories","Communicates defensively, hearing criticism in neutral statements"],growthPath:["Separating past emotional imprints from present-moment thinking","Using your emotional intelligence as a lens rather than a filter"]},"Mercury-Leo":{core:"You think in stories and you communicate with flair. Your ideas are bold and your delivery is theatrical, which makes you a natural presenter and storyteller. You need your ideas to be heard and acknowledged to feel intellectually alive.",strengths:["Compelling and dramatic communication","Creative thinking","Natural ability to inspire through words"],blindSpots:["Taking intellectual disagreement personally","Overshadowing others ideas in conversation"],underStress:["Becomes mentally rigid and dismisses any idea that challenges their authority","Speaks louder and more dramatically to reclaim attention when feeling ignored"],growthPath:["Celebrating others brilliant ideas with the same enthusiasm as your own","Trusting that your voice carries weight even when it is not the loudest in the room"]},"Mercury-Virgo":{core:"Your mind is a precision instrument, capable of analyzing and organizing information with extraordinary skill. You notice errors and inconsistencies that others miss entirely, and you communicate with clarity and specificity. Your standards for accuracy are exceptionally high.",strengths:["Exceptional analytical ability","Clear and precise communication","Talent for editing and improving"],blindSpots:["Analysis paralysis","Overthinking that delays action"],underStress:["Gets trapped in endless loops of analysis, unable to reach a conclusion","Becomes hyper-critical in speech, nitpicking details as a way to manage anxiety"],growthPath:["Knowing when an idea is good enough to act on without perfecting every detail","Applying your analytical gift with gentleness, especially toward yourself"]},"Mercury-Libra":{core:"You think in terms of balance, fairness, and how ideas relate to each other. Your communication style is diplomatic and measured, and you have a natural ability to see multiple sides of any argument. You genuinely enjoy the art of conversation and debate.",strengths:["Diplomatic communication","Ability to mediate and find compromise","Elegant and persuasive reasoning"],blindSpots:["Indecisiveness from weighing too many options","Avoiding confrontation in intellectual disputes"],underStress:["Becomes mentally paralyzed by the need to consider every perspective before deciding","Softens their real opinion so much it disappears entirely"],growthPath:["Making intellectual commitments even when not every angle has been explored","Speaking your unfiltered truth and trusting that grace will carry it"]},"Mercury-Scorpio":{core:"Your mind goes straight to the hidden truth beneath the surface. You are a natural researcher, investigator, and strategist, and your communication carries a penetrating intensity. You do not do small talk; you want the real conversation.",strengths:["Penetrating insight","Strategic and resourceful thinking","Ability to uncover hidden information"],blindSpots:["Suspicion that borders on paranoia","Using words as weapons when threatened"],underStress:["Becomes mentally obsessive and reads hidden motives into every interaction","Weaponizes knowledge and uses cutting words to regain a sense of power"],growthPath:["Using your investigative mind to understand rather than to control","Communicating difficult truths with precision and compassion in equal measure"]},"Mercury-Sagittarius":{core:"You think in big pictures and grand philosophies. Your mind craves meaning and your communication style is enthusiastic and expansive. You are the one who asks the question that changes the entire direction of the conversation.",strengths:["Visionary thinking","Inspiring and enthusiastic communication","Ability to synthesize broad concepts"],blindSpots:["Overlooking important details","Exaggeration in service of a good story"],underStress:["Becomes intellectually dogmatic and refuses to entertain dissenting views","Exaggerates and over-generalizes to force a narrative that makes sense of chaos"],growthPath:["Grounding visionary ideas with enough detail to make them actionable","Staying curious and open even when your current worldview feels threatened"]},"Mercury-Capricorn":{core:"Your mind is structured, strategic, and oriented toward results. You do not waste words, and when you speak, people listen because they know you have thought it through. Your intellectual authority comes from discipline, not flash.",strengths:["Structured and strategic thinking","Authoritative communication","Ability to plan long-term"],blindSpots:["Dismissing ideas that seem impractical","Pessimistic thinking patterns"],underStress:["Defaults to rigid, worst-case thinking and shuts down creative solutions","Becomes verbally terse and dismissive, cutting off communication when overwhelmed"],growthPath:["Allowing room for imaginative and unconventional ideas alongside practical ones","Softening authoritative speech with warmth so your wisdom is received, not resisted"]},"Mercury-Aquarius":{core:"You think in ways that genuinely surprise people. Your mind operates outside conventional frameworks, making unexpected connections and arriving at original conclusions. You communicate your ideas with conviction, even when they challenge the status quo.",strengths:["Innovative and original thinking","Ability to think systemically","Unbiased intellectual openness"],blindSpots:["Intellectual contrarianism for its own sake","Difficulty communicating ideas in accessible ways"],underStress:["Becomes stubbornly fixed on unconventional ideas and refuses to translate them for others","Detaches from the emotional context of conversations and argues purely from principle"],growthPath:["Bridging the gap between visionary thinking and relatable communication","Valuing emotional intelligence as a complement to intellectual originality"]},"Mercury-Pisces":{core:"Your mind works through images, feelings, and intuition rather than linear logic. You absorb information holistically and often know things without being able to explain how. Your communication is poetic, metaphorical, and deeply empathetic.",strengths:["Intuitive and creative thinking","Poetic communication","Ability to understand unspoken feelings"],blindSpots:["Difficulty with precise or technical communication","Absorbing others thoughts as your own"],underStress:["Becomes mentally foggy and unable to articulate what they know intuitively","Retreats into fantasy thinking and loses grip on practical priorities"],growthPath:["Developing structures that give your intuitive insights a clear voice","Trusting your non-linear knowing while building skills in grounded communication"]},"Venus-Aries":{core:"You love with urgency and passion, and you fall fast when someone catches your attention. You are drawn to bold, independent partners and you need excitement and novelty to stay engaged. In love, you are refreshingly honest about what you want.",strengths:["Passionate and exciting lover","Direct about desires","Brave in pursuing love"],blindSpots:["Losing interest after the chase","Confusing intensity with depth"],underStress:["Picks fights with loved ones to test the strength of the bond","Impulsively pursues new attractions to escape relational discomfort"],growthPath:["Discovering that sustained devotion can be as thrilling as the chase","Channeling passionate energy into deepening existing bonds rather than starting new ones"]},"Venus-Taurus":{core:"Love for you is a sensory experience, built on touch, shared meals, beauty, and presence. You are deeply loyal and you build relationships that last because you invest in them with patience and devotion. You know that real love is grown, not found.",strengths:["Deeply loyal and devoted partner","Gift for creating beauty and comfort","Sensual and present in love"],blindSpots:["Possessiveness in relationships","Staying in comfortable but stagnant situations"],underStress:["Becomes possessive and clings tightly to partners out of fear of loss","Refuses to address relationship problems, burying them under comfort and routine"],growthPath:["Loving with open hands instead of a tight grip","Recognizing that growth and change within a relationship are signs of life, not threats"]},"Venus-Gemini":{core:"You fall in love with minds first, and you need intellectual stimulation as much as emotional connection. Flirtation is an art form for you, and your charm is versatile and playful. You need a partner who can be your lover and your best friend.",strengths:["Witty and charming partner","Keeps relationships fresh and interesting","Excellent communicator in love"],blindSpots:["Difficulty with emotional depth in early relationships","Flirtatiousness that creates insecurity"],underStress:["Becomes emotionally evasive and uses humor to deflect serious relationship conversations","Mentally detaches from the relationship and flirts with new possibilities"],growthPath:["Allowing emotional vulnerability to be as valued as intellectual connection","Bringing your full curiosity to one relationship rather than sampling many"]},"Venus-Cancer":{core:"You love with your whole heart and you need emotional safety to truly open up. Your nurturing instinct extends to everyone you care about, and you express love through caretaking and emotional attunement. Home is where your love lives.",strengths:["Deeply nurturing and devoted","Emotionally attuned to partners needs","Creates a loving home environment"],blindSpots:["Clinginess when feeling insecure","Mothering partners instead of partnering with them"],underStress:["Becomes emotionally needy and seeks constant reassurance of love","Withdraws affection and retreats into wounded silence when feeling rejected"],growthPath:["Building a sense of emotional home within yourself that no one can take away","Expressing needs directly instead of hoping your partner will intuit them"]},"Venus-Leo":{core:"You love like it is a grand production, with big gestures, fierce loyalty, and unwavering devotion. You need to feel adored and special in your relationships, and in return, you make your partner feel like the center of the universe.",strengths:["Generous and warm-hearted lover","Unwavering loyalty","Makes love feel like an adventure"],blindSpots:["Need for constant admiration","Dramatic reactions to feeling unappreciated"],underStress:["Creates dramatic scenes to test whether their partner truly cares","Withholds their signature warmth and generosity as a form of punishment"],growthPath:["Loving without keeping score of how much adoration comes back","Finding that true royalty lies in lifting your partner up, not requiring them to bow"]},"Venus-Virgo":{core:"You show love through the small things: remembering preferences, helping with tasks, noticing when something is wrong before anyone says a word. Your love is humble and devoted, expressed through daily acts of care rather than grand gestures.",strengths:["Thoughtful and attentive partner","Devoted to improving the relationship","Reliable and consistent in love"],blindSpots:["Criticism disguised as help","Difficulty accepting imperfection in partners"],underStress:["Becomes hyper-critical of their partner as anxiety rises","Withdraws into quiet martyrdom, doing everything while resenting the lack of reciprocity"],growthPath:["Offering love without attaching conditions of improvement","Accepting your partner as they are while gently inviting growth together"]},"Venus-Libra":{core:"Partnership is your natural state. You are at your most alive when you are sharing your life with someone, and you bring grace, fairness, and beauty to every relationship. You have an innate understanding of what makes relationships work.",strengths:["Natural relationship harmony","Romantic and attentive partner","Fair and balanced in love"],blindSpots:["Losing identity in relationships","Avoiding necessary conflict to keep the peace"],underStress:["Bends over backward to accommodate and disappears into the relationship","Avoids all confrontation until resentment quietly poisons the connection"],growthPath:["Maintaining a strong sense of self within the beauty of partnership","Embracing loving conflict as a pathway to deeper intimacy"]},"Venus-Scorpio":{core:"You love with an intensity that can be overwhelming for those who are not ready for it. You want all or nothing, total emotional and physical merging with your partner. Trust is your love language, and once given, your devotion is absolute.",strengths:["Deeply passionate and committed","Emotionally brave in love","Transformative intimacy"],blindSpots:["Jealousy and control in relationships","Testing partners loyalty"],underStress:["Becomes consumed by jealousy and monitors the relationship obsessively","Emotionally punishes perceived disloyalty with cold withdrawal or confrontation"],growthPath:["Trusting without needing to test or verify your partner constantly","Allowing love to be a space of surrender rather than a territory to defend"]},"Venus-Sagittarius":{core:"You need love to feel like an adventure, not a cage. You are drawn to partners who expand your world, challenge your beliefs, and are willing to explore alongside you. Your love is generous, honest, and delightfully spontaneous.",strengths:["Adventurous and fun-loving partner","Honest and open in love","Generous with freedom and trust"],blindSpots:["Fear of commitment and routine","Tactless honesty that hurts partners"],underStress:["Emotionally bolts and creates distance when relationships feel too binding","Becomes bluntly critical of the relationship rather than working through discomfort"],growthPath:["Discovering that commitment is not a cage but a launchpad for deeper adventure","Wrapping honesty in enough tenderness that it heals rather than wounds"]},"Venus-Capricorn":{core:"You take love seriously and you build relationships with the same care and ambition you bring to everything else. You are not interested in flings; you want a partnership that stands the test of time. Your love deepens steadily with the years.",strengths:["Loyal and committed partner","Builds lasting relationship foundations","Shows love through actions and stability"],blindSpots:["Emotional reserve that feels like distance","Prioritizing achievement over connection"],underStress:["Shuts down emotionally and throws themselves into work as a coping mechanism","Becomes controlling about relationship structure and timelines"],growthPath:["Allowing love to be unstructured and spontaneous sometimes","Showing your tender heart before you have proof that it is safe"]},"Venus-Aquarius":{core:"You love in unconventional ways and you need a partner who respects your independence above all. Friendship is the foundation of your romantic relationships, and you are drawn to people who are different, original, and unafraid to be themselves.",strengths:["Respects partners individuality","Open-minded and accepting in love","Values friendship within romance"],blindSpots:["Emotional detachment in intimate moments","Intellectualizing love instead of feeling it"],underStress:["Retreats into emotional detachment and treats the relationship like a concept to analyze","Prioritizes personal freedom so fiercely that their partner feels abandoned"],growthPath:["Letting yourself be emotionally dependent on someone without losing your identity","Discovering that true freedom in love comes from depth, not distance"]},"Venus-Pisces":{core:"You love without boundaries, with a tenderness and compassion that can feel almost otherworldly. You see the best in your partners and you give yourself completely to love. Your romantic nature is one of the most beautiful and vulnerable in the zodiac.",strengths:["Unconditional and compassionate love","Deep romantic imagination","Selfless devotion to partners"],blindSpots:["Idealizing partners beyond reality","Sacrificing yourself to save a relationship"],underStress:["Loses themselves completely in the other person and forgets their own needs exist","Escapes into romantic fantasy rather than addressing painful relationship realities"],growthPath:["Loving with clear eyes as well as an open heart","Learning that the most sacred devotion includes unwavering devotion to yourself"]},"Mars-Aries":{core:"Your drive is raw, instinctive, and immediate. When you want something, you go after it without hesitation, and your competitive fire is a force of nature. You are at your most powerful when you have a clear target and the freedom to charge.",strengths:["Explosive initiative and drive","Fearless in competition","Quick and decisive action"],blindSpots:["Aggression that burns bridges","Starting things you do not finish"],underStress:["Becomes volatile and explosive, acting out of rage rather than purpose","Pushes past every limit and burns out in spectacular fashion"],growthPath:["Directing your warrior energy toward causes greater than personal conquest","Learning that strategic patience amplifies the power of your strike"]},"Mars-Taurus":{core:"Your drive is slow-building but unstoppable once it gets moving. You pursue your goals with a patient, relentless determination that outlasts everyone else. You will not be rushed, and once you commit, nothing short of an earthquake will move you.",strengths:["Incredible stamina and persistence","Calm under pressure","Steady and reliable effort"],blindSpots:["Stubbornness that prevents adaptation","Slow to act when urgency is needed"],underStress:["Becomes an immovable wall and refuses to engage with any new approach","Channels frustration into excessive material indulgence or physical inertia"],growthPath:["Recognizing when persistence becomes resistance and knowing the difference","Allowing urgency to accelerate your natural rhythm without abandoning it"]},"Mars-Gemini":{core:"Your energy is mental and versatile, expressed through words, ideas, and rapid multitasking. You fight with your intellect and you pursue your goals through communication and cleverness. You need variety in how you channel your energy.",strengths:["Quick-witted under pressure","Versatile approach to challenges","Effective communicator in conflict"],blindSpots:["Scattered effort across too many goals","Using words to avoid direct action"],underStress:["Becomes argumentative and uses sharp words as weapons","Disperses energy in so many directions that nothing meaningful gets accomplished"],growthPath:["Focusing your versatile energy on fewer goals with greater follow-through","Choosing when to wield your words and when to let action speak instead"]},"Mars-Cancer":{core:"Your drive is deeply emotional and protective. You are at your most powerful when you are defending someone you love or fighting for your sense of security. Your energy waxes and wanes with your moods, but when fully engaged, your tenacity is formidable.",strengths:["Fierce protectiveness","Emotional stamina","Intuitive timing in action"],blindSpots:["Passive-aggressive tendencies","Emotional volatility that disrupts focus"],underStress:["Becomes passive-aggressive and manipulates through guilt instead of direct confrontation","Retreats into emotional shutdown and refuses to engage with the source of conflict"],growthPath:["Expressing anger directly and cleanly instead of sideways","Harnessing emotional tides as fuel rather than being capsized by them"]},"Mars-Leo":{core:"You pursue your ambitions with dramatic flair and unshakeable confidence. Your competitive drive is tied to your sense of pride and self-expression, and you perform best when people are watching. You were born to lead and inspire through action.",strengths:["Confident and charismatic drive","Natural leadership in action","Courage that inspires others"],blindSpots:["Ego-driven decisions","Difficulty accepting defeat gracefully"],underStress:["Becomes tyrannical and makes everything about wounded pride","Refuses to back down from losing battles because surrender feels like humiliation"],growthPath:["Leading with humility and letting results speak louder than performance","Finding that true courage includes the grace to step back when needed"]},"Mars-Virgo":{core:"Your drive is precise, methodical, and efficient. You pursue your goals through careful planning and flawless execution, and you channel your energy into being genuinely useful. Your work ethic is quietly extraordinary.",strengths:["Meticulous and efficient effort","Disciplined work ethic","Problem-solving under pressure"],blindSpots:["Perfectionism that slows progress","Critical of others methods and effort"],underStress:["Becomes obsessively focused on minor flaws and loses sight of the larger goal","Criticizes everyone else s effort while silently overworking themselves to exhaustion"],growthPath:["Trusting that done well is often better than done perfectly","Channeling your precision toward what matters most and releasing the rest"]},"Mars-Libra":{core:"You channel your energy into creating fairness, beauty, and harmony. You fight for justice and you pursue your goals through collaboration and charm. Direct confrontation is uncomfortable for you, so you achieve your aims through strategy and persuasion.",strengths:["Diplomatic approach to conflict","Strategic and fair-minded action","Ability to motivate through charm"],blindSpots:["Indecisiveness that stalls action","Passive avoidance of necessary confrontation"],underStress:["Freezes in the face of conflict and defers decisions to avoid blame","Builds silent resentment from constantly choosing peace over truth"],growthPath:["Taking decisive action even when consensus is not yet reached","Discovering that direct confrontation can be an act of love and respect"]},"Mars-Scorpio":{core:"Your drive is intense, strategic, and relentless. When you set your sights on something, you pursue it with a laser focus that can be intimidating. You are not afraid of power, and you understand that real strength is quiet and controlled.",strengths:["Intense focus and willpower","Strategic and resourceful action","Emotional power in pursuit of goals"],blindSpots:["Vengeful tendencies when crossed","Obsessive pursuit that ignores cost"],underStress:["Becomes ruthlessly fixated on domination and winning at any cost","Plots revenge quietly and channels all energy into settling perceived scores"],growthPath:["Using your formidable will to transform yourself rather than control outcomes","Releasing the need for revenge and redirecting that energy toward creation"]},"Mars-Sagittarius":{core:"Your energy is expansive, adventurous, and guided by a sense of purpose. You fight for your beliefs and you pursue goals that carry meaning beyond personal gain. Your enthusiasm is contagious and your courage knows few limits.",strengths:["Adventurous and bold action","Enthusiastic pursuit of goals","Moral courage and conviction"],blindSpots:["Overcommitting to too many ventures","Recklessness disguised as bravery"],underStress:["Takes reckless risks and acts impulsively to escape feelings of confinement","Becomes self-righteous and crusades aggressively for their beliefs"],growthPath:["Directing your expansive energy into completing what you start before chasing the next horizon","Fighting for your beliefs with the same openness you want others to show yours"]},"Mars-Capricorn":{core:"Your drive is disciplined, ambitious, and strategically focused on long-term success. You do not waste energy on things that will not get results, and your ability to work tirelessly toward your goals is one of your greatest assets.",strengths:["Strategic and disciplined ambition","Exceptional endurance","Calm authority in action"],blindSpots:["Ruthlessness in pursuit of goals","Suppressing personal needs for achievement"],underStress:["Becomes coldly calculating and treats people as obstacles or instruments","Works themselves into the ground, refusing to stop until the body forces a breakdown"],growthPath:["Aligning ambition with values so that success nourishes rather than depletes","Allowing yourself to move toward a goal at a human pace with room for rest"]},"Mars-Aquarius":{core:"You channel your energy into innovation, rebellion, and collective progress. You fight for causes bigger than yourself and you pursue goals in unconventional ways. Your independence in action is fierce and non-negotiable.",strengths:["Innovative approach to challenges","Fights for collective good","Independent and original action"],blindSpots:["Contrarian actions that isolate you","Emotional detachment from personal drive"],underStress:["Becomes rebellious without direction and tears down structures with nothing to replace them","Disconnects from personal motivation and acts only from ideology"],growthPath:["Building as fiercely as you are willing to dismantle","Connecting your fight for the collective to the personal passion that fuels it"]},"Mars-Pisces":{core:"Your drive is fluid, intuitive, and guided by inspiration rather than logic. You are most motivated when you are connected to a creative or spiritual purpose, and your energy works best when you surrender to flow rather than forcing outcomes.",strengths:["Creative and inspired action","Compassionate motivation","Adaptable energy"],blindSpots:["Difficulty with direct confrontation","Passive approach when assertiveness is needed"],underStress:["Becomes paralyzed by indirection and withdraws into passive avoidance","Loses all motivation and drifts aimlessly when disconnected from a sense of meaning"],growthPath:["Developing a structure that holds your creative flow without constraining it","Standing your ground with gentle firmness when the moment calls for assertion"]}};function g(e,t){return c[`${e}-${t}`]||null}const P=Object.freeze(Object.defineProperty({__proto__:null,getPlanetInSign:g},Symbol.toStringTag,{value:"Module"})),u={"Sun-1":{expression:"Your identity and your outward presentation are closely fused; what people see is genuinely what they get. You radiate a strong sense of self that naturally draws attention and sets the tone in any room you enter.",themes:["Self-expression and personal identity","Physical vitality and presence","Leadership through being rather than doing"],healthy:"You lead with authentic confidence and inspire others simply by being fully yourself.",unhealthy:"You become self-absorbed and domineering, demanding constant attention and refusing to make room for anyone else."},"Sun-2":{expression:"Your sense of self is intimately tied to what you build, earn, and value. You shine brightest when you are creating material or emotional security, and your self-worth grows as you learn to trust your own resources.",themes:["Financial identity and earning power","Personal values as life compass","Building tangible self-worth"],healthy:"You build genuine self-worth from within and use your resources generously to support what you truly value.",unhealthy:"You equate your identity entirely with material wealth and become possessive, hoarding resources out of deep insecurity."},"Sun-3":{expression:"You come alive through learning, communicating, and connecting the dots between ideas. Your identity is shaped by your immediate environment, siblings, and the daily exchanges that keep your mind buzzing.",themes:["Communication as core identity","Sibling and neighborhood bonds","Lifelong learning and curiosity"],healthy:"You share knowledge with genuine curiosity and use your words to build bridges between people and ideas.",unhealthy:"You scatter your energy across too many superficial interests and use cleverness to manipulate rather than connect."},"Sun-4":{expression:"Home and family are the foundation upon which your entire identity rests. You carry your roots with you wherever you go, and creating a sense of belonging is one of the most important things you will ever do.",themes:["Deep connection to family origins","Home as sanctuary and identity","Emotional foundations shaping adult self"],healthy:"You create a warm, nurturing home environment and draw strength from your roots while allowing yourself to grow beyond them.",unhealthy:"You cling to the past and use family loyalty as a way to avoid the vulnerability of forging your own independent identity."},"Sun-5":{expression:"You are here to create, play, and express your heart without apology. Romance, children, art, and joy are not luxuries for you but essential parts of how you experience being alive.",themes:["Creative self-expression and joy","Romance and playful love","Children and creative legacy"],healthy:"You channel your creative fire into art, love, and play that uplifts both yourself and those around you.",unhealthy:"You chase constant drama and validation through romantic conquests or attention-seeking displays, unable to find joy within."},"Sun-6":{expression:"You find your purpose through service, health, and the daily rituals that make life work. Your identity is shaped by how useful you feel, and you shine when your skills are genuinely helping someone.",themes:["Service and meaningful work","Health as spiritual practice","Mastery of daily routines"],healthy:"You serve others with skill and humility, finding deep satisfaction in the craft of making everyday life work beautifully.",unhealthy:"You become a perfectionist workaholic who criticizes everyone, including yourself, and ties all self-worth to productivity."},"Sun-7":{expression:"You discover who you are through the mirror of your closest relationships. Partnership is not optional for your growth; it is the crucible where your identity is refined and revealed.",themes:["Identity through partnership","Balancing self and other","Committed relationships as life teachers"],healthy:"You bring your full self to partnerships and grow through the honest give-and-take of committed relationships.",unhealthy:"You lose yourself entirely in others, becoming dependent on a partner to define who you are and unable to stand alone."},"Sun-8":{expression:"You are drawn to the hidden, the taboo, and the transformative. Your identity is forged in crisis and rebirth, and you have a gift for navigating the dark terrain that others avoid.",themes:["Transformation through crisis","Shared resources and intimacy","Power dynamics and trust"],healthy:"You face life's depths with courage and use your transformative experiences to help others through their own dark passages.",unhealthy:"You become obsessed with control and power, manipulating others through secrecy and emotional intensity to avoid your own vulnerability."},"Sun-9":{expression:"You need your life to mean something, and you find identity through philosophy, travel, and the pursuit of truth. Your world expands every time you encounter a perspective different from your own.",themes:["Search for meaning and truth","Travel and cross-cultural growth","Higher education and philosophy"],healthy:"You pursue wisdom with an open mind and share your expansive worldview in ways that genuinely broaden others' horizons.",unhealthy:"You become a self-righteous preacher who believes only your truth matters and uses philosophy to avoid the messy details of real life."},"Sun-10":{expression:"Your public role and career are not just what you do; they are who you are. You have a natural authority and a deep need to build something that the world recognizes and respects.",themes:["Career as identity and calling","Public reputation and authority","Legacy and long-term ambition"],healthy:"You lead with integrity and build a public legacy that reflects your authentic values and serves the greater good.",unhealthy:"You sacrifice personal relationships and inner life on the altar of ambition, defining yourself solely by status and external achievement."},"Sun-11":{expression:"You find yourself through community, friendship, and shared visions of the future. Your identity thrives when it is connected to something larger than yourself, a cause, a group, a dream for what could be.",themes:["Community and social purpose","Friendship as lifeblood","Hopes, wishes, and collective vision"],healthy:"You contribute your unique gifts to a community vision and form friendships that inspire both personal and collective growth.",unhealthy:"You hide behind group identity to avoid personal accountability and become so focused on ideals that you neglect the people right in front of you."},"Sun-12":{expression:"Much of who you are lives beneath the surface, in the realm of dreams, intuition, and the unconscious. You are learning to shine from the inside out, and your greatest power comes from solitude and spiritual connection.",themes:["Inner life and spiritual identity","Hidden strengths and secret gifts","Healing through surrender and solitude"],healthy:"You cultivate a rich inner life and use your deep sensitivity to bring compassion and spiritual insight to the world.",unhealthy:"You retreat into isolation and escapism, losing yourself in fantasy or addiction because the material world feels too harsh to bear."},"Moon-1":{expression:"Your emotions are written all over your face, and your mood sets the atmosphere wherever you go. You are deeply in touch with your feelings and you process life through an instinctive, emotional lens.",themes:["Emotional transparency","Instinctive self-expression","Mood as personal weather system"],healthy:"You honor your emotional nature openly, creating authentic connections through your willingness to be emotionally present and visible.",unhealthy:"You become a slave to mood swings, projecting your emotional storms onto everyone around you and taking everything personally."},"Moon-4":{expression:"Home is your emotional anchor, and your inner world is shaped by your earliest memories and family dynamics. You carry your childhood with you in ways both beautiful and complicated, and creating a nurturing home is essential to your well-being.",themes:["Deep family emotional bonds","Home as emotional sanctuary","Healing ancestral emotional patterns"],healthy:"You create a deeply nurturing home life and consciously heal inherited family patterns so they are not passed on.",unhealthy:"You remain emotionally enmeshed with your family of origin, unable to set boundaries or move beyond childhood wounds."},"Moon-7":{expression:"You need emotional partnership like you need air. Your feelings are deeply activated in close relationships, and you have an instinctive ability to attune to your partner emotional state.",themes:["Emotional fulfillment through partnership","Intuitive connection with partners","Codependency versus healthy bonding"],healthy:"You form deeply attuned emotional partnerships where mutual care and vulnerability create genuine intimacy.",unhealthy:"You become emotionally codependent, losing your own emotional center by absorbing your partner's feelings as your own."},"Moon-10":{expression:"Your emotional life and your public life are intertwined in complex ways. You bring genuine feeling to your career, and your professional reputation is built on the authentic care you show in your work.",themes:["Emotional investment in career","Public nurturing role","Mother figures and professional identity"],healthy:"You bring genuine emotional intelligence to your professional life, earning public trust through authentic care and sensitivity.",unhealthy:"You seek emotional validation through career achievement and public approval, neglecting your private emotional needs until they erupt publicly."},"Venus-5":{expression:"Love and creativity are your lifeblood, and you experience both with a natural flair that makes life feel like art. Romance is not a sideshow for you but the main event, and you attract love through your joyful self-expression.",themes:["Romantic creativity and passion","Artistic talent and aesthetic joy","Love affairs and playful connection"],healthy:"You express love and creativity with generous warmth, turning everyday moments into something beautiful for yourself and others.",unhealthy:"You become addicted to the thrill of new romance and external admiration, unable to sustain love once the initial sparkle fades."},"Venus-7":{expression:"Partnership comes naturally to you, and you have a gift for creating harmonious, beautiful relationships. You are at your most attractive when you are in love, and you bring grace and balance to every committed bond.",themes:["Natural partnership harmony","Attracting loving relationships","Beauty and balance in commitment"],healthy:"You cultivate relationships built on mutual respect and genuine harmony, bringing grace and fairness to every partnership.",unhealthy:"You avoid all conflict to maintain a surface-level peace, compromising your own needs and values to keep a relationship looking perfect."},"Mars-1":{expression:"You approach life as a warrior, meeting every challenge head-on with physical energy and assertive confidence. Your body is your vehicle for action, and people sense your competitive, driven nature immediately.",themes:["Physical assertiveness and courage","Competitive drive and initiative","Body as instrument of will"],healthy:"You channel your fierce energy into courageous action and inspire others through your bold, direct approach to life.",unhealthy:"You become recklessly aggressive, picking fights and bulldozing over others because you confuse domination with strength."},"Mars-10":{expression:"Your ambition is fierce and your drive for professional success is one of the defining forces of your life. You need a career that lets you compete, lead, and pour your considerable energy into building something that matters.",themes:["Ambitious career drive","Professional leadership and authority","Channeling aggression into achievement"],healthy:"You pursue professional goals with disciplined intensity and lead others through decisive, courageous action.",unhealthy:"You become ruthlessly competitive in your career, burning bridges and treating people as obstacles to be conquered on your climb to the top."},"Jupiter-9":{expression:"This is one of the most naturally fortunate placements, amplifying your love of learning, travel, and spiritual growth. Your faith in life is expansive, and you attract opportunities through your genuine openness to the world.",themes:["Expansive philosophical vision","Luck through travel and education","Spiritual optimism and growth"],healthy:"You inspire others with your generous wisdom and use your good fortune to open doors for those who have fewer opportunities.",unhealthy:"You over-extend yourself with grandiose promises, become preachy about your beliefs, and rely on luck rather than doing the necessary work."},"Saturn-10":{expression:"You carry a heavy sense of responsibility about your place in the world and your professional legacy. Success comes to you through discipline, patience, and a willingness to do the hard work that others avoid, often later in life.",themes:["Disciplined long-term ambition","Authority earned through perseverance","Late-blooming professional success"],healthy:"You build lasting professional authority through patience, integrity, and a willingness to earn every ounce of respect you receive.",unhealthy:"You become cold and rigid in your pursuit of status, sacrificing warmth and human connection for a legacy built on fear rather than respect."}},y={Sun:"identity and purpose",Moon:"emotional needs and instincts",Mercury:"thinking and communication",Venus:"love and values",Mars:"drive and assertion",Jupiter:"expansion and growth",Saturn:"discipline and responsibility",Uranus:"innovation and disruption",Neptune:"imagination and transcendence",Pluto:"transformation and power"},m={1:"self-image and first impressions",2:"finances, possessions, and self-worth",3:"communication, learning, and local community",4:"home, family, and emotional roots",5:"creativity, romance, and self-expression",6:"daily work, health, and service",7:"partnerships and committed relationships",8:"shared resources, intimacy, and transformation",9:"philosophy, travel, and higher learning",10:"career, reputation, and public life",11:"friendships, community, and future vision",12:"spirituality, solitude, and the unconscious"};function p(e,t){return u[`${e}-${t}`]||null}function f(e,t){const n=u[`${e}-${t}`];if(n)return n;const o=y[e]||"personal energy",i=m[t]||"this area of life";return{expression:`Your ${o} finds its primary outlet through the realm of ${i}. This placement asks you to integrate these themes into a conscious part of your daily experience.`,themes:[`${e} energy expressed through ${i}`,`Growth through engaging with house ${t} matters`,`Integrating ${o} into practical life`],healthy:`You channel your ${o} constructively through ${i}, finding authentic fulfillment in this area of life.`,unhealthy:`You misuse your ${o} in the domain of ${i}, either avoiding it entirely or expressing it in compulsive, unconscious ways.`}}const M=Object.freeze(Object.defineProperty({__proto__:null,getGenericHouseInterp:f,getPlanetInHouse:p},Symbol.toStringTag,{value:"Module"})),r={"Sun-Moon-conjunction":{meaning:"Your conscious identity and emotional needs are fused into one powerful force. You know what you want and what you feel with unusual clarity.",howItFeels:"A sense of inner unity and emotional directness, though sometimes you struggle to see yourself objectively because your ego and emotions speak in the same voice."},"Sun-Moon-opposition":{meaning:"There is a fundamental tension between who you are and what you need. Your head and heart often pull in different directions, creating a rich inner dialogue.",howItFeels:"A constant balancing act between your public self and your private emotional world, like living with two equally valid but competing inner voices."},"Sun-Moon-trine":{meaning:"Your identity and emotional life flow together with ease. What you want and what you feel are naturally aligned, giving you an effortless inner harmony.",howItFeels:"A quiet confidence that comes from not being at war with yourself, a natural alignment between your mind and heart that others can sense."},"Sun-Moon-square":{meaning:"Your will and your emotions are in creative friction, constantly pushing each other to grow. This inner tension is uncomfortable but incredibly productive.",howItFeels:"An ongoing push-pull between what you think you should want and what you actually feel, creating a restless energy that drives personal growth."},"Sun-Venus-conjunction":{meaning:"Love, beauty, and charm are woven directly into your identity. You naturally attract others and you express yourself with warmth and grace.",howItFeels:"An effortless likability and a deep need to be appreciated, as if your very sense of self is enhanced by beauty and connection."},"Sun-Venus-trine":{meaning:"There is a natural ease between your identity and your capacity for love and pleasure. You attract good things into your life without forcing them.",howItFeels:"A gentle magnetism and appreciation for life pleasures that makes relationships and creative pursuits feel naturally rewarding."},"Sun-Venus-square":{meaning:"Your desire for love and approval sometimes conflicts with your authentic self-expression. You are learning that being liked and being yourself can coexist.",howItFeels:"A tension between wanting to please others and needing to honor your own truth, often showing up most clearly in relationships and creative choices."},"Sun-Mars-conjunction":{meaning:"Your identity and your drive are fused into a powerful, action-oriented force. You are assertive, competitive, and you define yourself through what you do.",howItFeels:"An almost physical need to act, compete, and assert yourself, as if sitting still feels like a betrayal of who you are."},"Sun-Mars-opposition":{meaning:"You project your assertive energy outward, often attracting conflict or competition from others. Learning to own your own aggression is a major life theme.",howItFeels:"Encounters with strong-willed people who mirror the assertive energy you may not fully claim in yourself, creating dynamic but challenging relationships."},"Sun-Mars-trine":{meaning:"Your willpower and your drive work together effortlessly, giving you a natural athleticism and competitive edge. You act with confidence and purpose.",howItFeels:"A clean, direct energy that allows you to go after what you want without second-guessing, a feeling of alignment between intention and action."},"Sun-Mars-square":{meaning:"There is friction between your identity and your aggressive instincts, creating a restless, sometimes volatile energy that demands a healthy outlet.",howItFeels:"An inner irritation that needs channeling through physical activity, competition, or courageous action, otherwise it turns inward as frustration."},"Sun-Jupiter-conjunction":{meaning:"Optimism, faith, and expansion are central to who you are. You have a natural bigness of spirit that draws opportunities and good fortune toward you.",howItFeels:"A buoyant confidence and a sense that life is fundamentally generous, as if the universe has a soft spot for your particular journey."},"Sun-Jupiter-trine":{meaning:"Growth and opportunity flow easily into your life. Your natural optimism and generosity create a positive feedback loop that attracts abundance.",howItFeels:"A sense of being supported by life, as if doors open just when you need them and your faith in good outcomes is regularly rewarded."},"Sun-Jupiter-square":{meaning:"Your desire for growth and expansion sometimes exceeds practical limits. You dream big, sometimes too big, and learning moderation is a lifelong theme.",howItFeels:"A restless urge to overextend, overcommit, or overindulge, combined with a genuine optimism that makes it hard to say no to possibilities."},"Sun-Saturn-conjunction":{meaning:"Responsibility, discipline, and maturity are fused into your core identity. You carry a seriousness that others respect, and you earn everything you have.",howItFeels:"A weight of responsibility that has been with you since childhood, paired with a quiet determination that grows stronger with age."},"Sun-Saturn-opposition":{meaning:"Authority figures and external structures challenge your sense of self. You are learning to build your own authority rather than deferring to or rebelling against others.",howItFeels:"A feeling of being tested by life, as if you must constantly prove your worth against external standards and expectations."},"Sun-Saturn-trine":{meaning:"Discipline and ambition support your identity naturally. You have a mature, grounded quality that inspires trust and you build things that last.",howItFeels:"A steady confidence rooted in competence and hard work, a feeling that time is your ally and your efforts will pay off."},"Sun-Saturn-square":{meaning:"There is deep friction between your desire to shine and an inner voice that says you are not good enough. Overcoming self-doubt is your heroic journey.",howItFeels:"A persistent inner critic that demands you earn every ounce of self-worth, creating a driven, sometimes anxious relationship with success."},"Moon-Venus-conjunction":{meaning:"Your emotional needs and your desire for love and beauty are one and the same. You crave tenderness, harmony, and aesthetic pleasure at the deepest level.",howItFeels:"A soft, loving emotional nature that seeks beauty and connection as essential nourishment, making you both deeply romantic and easily wounded."},"Moon-Venus-trine":{meaning:"Love and emotional comfort flow together naturally. Your relationships are nourished by genuine warmth, and you create beauty in your home and emotional life effortlessly.",howItFeels:"An easy warmth in your emotional world that makes others feel comfortable and loved in your presence, a natural gift for emotional grace."},"Moon-Venus-square":{meaning:"Your emotional needs and your desires in love sometimes pull in different directions. What comforts you and what attracts you may not always be the same thing.",howItFeels:"A tension between emotional security and romantic desire, as if what feels safe and what feels exciting are located in different places."},"Moon-Mars-conjunction":{meaning:"Your emotions are fiery, immediate, and action-oriented. You feel things with a physical intensity that demands expression, and your emotional reactions are swift and powerful.",howItFeels:"A volatile emotional energy that moves quickly from feeling to acting, giving you passionate intensity but also a hair-trigger emotional response."},"Moon-Mars-square":{meaning:"There is friction between your need for safety and your instinct for action. Your emotions can feel like an internal battleground between vulnerability and aggression.",howItFeels:"Emotional restlessness and irritability that erupts when you feel your security is threatened, a need to channel strong feelings into physical outlets."},"Moon-Saturn-conjunction":{meaning:"Your emotional world is structured by responsibility and restraint. You learned early to contain your feelings, and emotional maturity comes naturally but at a cost.",howItFeels:"A seriousness in your emotional life, as if you were born old and must learn to give yourself permission to feel freely and be vulnerable."},"Moon-Saturn-opposition":{meaning:"External duties and expectations press against your emotional needs, creating a tension between what you feel and what you believe is responsible.",howItFeels:"A pull between your private emotional world and public obligations, as if allowing yourself to feel openly is somehow irresponsible."},"Moon-Saturn-square":{meaning:"Your emotional expression is blocked or delayed by fear, duty, or early conditioning. Learning to let yourself feel without judgment is transformative work.",howItFeels:"A deep emotional caution, as if a part of you is always bracing for disappointment, making vulnerability feel dangerous rather than connecting."},"Venus-Mars-conjunction":{meaning:"Your desire nature is powerful and unified. What you love and what you pursue are fused together, giving you a magnetic, passionate presence in relationships.",howItFeels:"An intense, charismatic energy that draws others in, combining receptive charm with active pursuit in a way that is both attractive and commanding."},"Venus-Mars-opposition":{meaning:"There is a dynamic tension between your feminine and masculine energies, between receiving and pursuing. Relationships are the arena where this polarity plays out most dramatically.",howItFeels:"A push-pull in relationships between wanting to be chased and wanting to chase, creating passionate dynamics that can be thrilling or exhausting."},"Venus-Mars-square":{meaning:"Your desires and your values are in friction, creating a charged, sometimes frustrated relationship with love and intimacy. The tension is uncomfortable but creatively potent.",howItFeels:"A restless dissatisfaction in love, as if what you want physically and what you want emotionally do not always align, driving you toward growth in relationships."},"Venus-Saturn-conjunction":{meaning:"Love is serious business for you. You approach relationships with maturity and commitment, and you are willing to do the work that real love requires.",howItFeels:"A cautious approach to love that deepens with time, as if you need to build trust brick by brick before you can truly let someone in."},"Venus-Saturn-square":{meaning:"Fear of rejection or unworthiness creates obstacles in your love life. You are learning that you deserve love not because you have earned it but simply because you exist.",howItFeels:"A feeling of not being enough in relationships, a tendency to withhold affection or choose partners who confirm your fear of not being lovable."},"Mars-Saturn-conjunction":{meaning:"Your drive is disciplined, controlled, and capable of extraordinary endurance. You channel your aggression into structured achievement, and your willpower is formidable.",howItFeels:"A controlled intensity, as if your energy runs through a narrow, powerful channel that produces focused results but can feel restrictive."},"Mars-Saturn-square":{meaning:"There is a deep frustration between your desire to act and forces that restrain you. Learning to work within limitations without losing your fire is your challenge.",howItFeels:"A stop-start quality to your energy, as if you are driving with one foot on the gas and one on the brake, creating tension that demands a release valve."},"Jupiter-Saturn-conjunction":{meaning:"The forces of expansion and contraction are merged in your psyche, creating a unique capacity to dream big and build practically at the same time.",howItFeels:"An oscillation between optimism and caution that ultimately produces balanced, sustainable growth when you learn to trust both voices."},"Jupiter-Saturn-opposition":{meaning:"Faith and doubt are in constant dialogue within you. You are pulled between the desire to expand and the need for structure, between risk and responsibility.",howItFeels:"A seesaw between feeling like anything is possible and fearing that nothing will work out, teaching you to find wisdom in the middle ground."},"Sun-Uranus-conjunction":{meaning:"Your identity is inseparable from your need to be different. Conformity feels like death to you, and you express your individuality with electric intensity.",howItFeels:"A restless, exciting energy that makes you feel most alive when you are breaking new ground or challenging expectations."},"Sun-Uranus-square":{meaning:"There is tension between your need for stability and your urge for radical freedom. Sudden disruptions to your identity force evolution and awakening.",howItFeels:"An unpredictable quality to your life, as if just when things settle, something within you rebels and demands a shakeup."},"Sun-Neptune-conjunction":{meaning:"Your identity is deeply intertwined with imagination, spirituality, and the desire to transcend ordinary life. You are sensitive to beauty and suffering in equal measure.",howItFeels:"A dreamy, permeable sense of self that can feel magical or confusing depending on the day, as if the boundaries between you and the world are thin."},"Sun-Neptune-square":{meaning:"There is friction between who you are and who you wish you could be. Idealism and reality clash, and you are learning to be inspired without being deluded.",howItFeels:"A persistent fog around your identity, as if you are not quite sure who you really are versus who you have been imagining yourself to be."},"Sun-Pluto-conjunction":{meaning:"Power, intensity, and transformation are at the core of who you are. You live life at full depth, and you have an almost compulsive need to uncover hidden truths.",howItFeels:"A profound intensity that colors everything you do, a sense that you are always in the process of destroying and rebuilding yourself."},"Sun-Pluto-square":{meaning:"Power struggles and control issues are woven into your identity. You are learning that real power comes from transformation, not domination.",howItFeels:"An intense inner pressure, as if something deep within you is constantly pushing for control while life demands that you surrender it."},"Moon-Pluto-conjunction":{meaning:"Your emotional world is volcanic, operating at depths that most people never reach. You experience feelings as transformative forces that change you from the inside out.",howItFeels:"An emotional intensity that can feel overwhelming, as if every feeling carries the weight of life and death and demands total honesty."},"Moon-Pluto-square":{meaning:"Deep emotional power struggles, often rooted in family dynamics, shape your inner world. You are learning to feel powerful without needing to control your emotional environment.",howItFeels:"A turbulent emotional undercurrent that surfaces in moments of intimacy, bringing up primal feelings of trust, betrayal, and the need for emotional truth."},"Moon-Neptune-conjunction":{meaning:"Your emotional world is boundless, dreamy, and deeply empathetic. You absorb the feelings of others like water, and your intuition borders on psychic.",howItFeels:"A soft, permeable emotional state that makes you incredibly compassionate but also vulnerable to emotional confusion and overwhelm."},"Moon-Neptune-square":{meaning:"Your emotional needs and your ideals are in tension, creating confusion about what you actually feel versus what you wish you felt.",howItFeels:"A foggy emotional landscape where it is hard to tell your feelings from others or reality from wishful thinking, requiring deliberate grounding."}},w={conjunction:"merges and intensifies",opposition:"creates tension and awareness between",trine:"harmonizes and eases the flow between",square:"creates friction and growth between",sextile:"gently supports and connects"};function v(e,t,n){return r[`${e}-${t}-${n}`]||r[`${t}-${e}-${n}`]||null}function b(e,t,n){const o=r[`${e}-${t}-${n}`]||r[`${t}-${e}-${n}`];return o||{meaning:`This aspect ${w[n]||"connects"} the energy of ${e} and ${t} in your chart. These two planetary forces are in active dialogue, shaping how you experience both energies in daily life.`,howItFeels:`You may notice the themes of ${e} and ${t} interacting in ways that feel ${n==="trine"||n==="sextile"?"supportive and natural":"challenging but growth-oriented"}, asking you to integrate both energies consciously.`}}const I=Object.freeze(Object.defineProperty({__proto__:null,getAspectInterp:v,getGenericAspectInterp:b},Symbol.toStringTag,{value:"Module"})),h={"Jupiter-Sun-conjunction":{theme:"A year of expansion, confidence, and new beginnings in your sense of self.",feeling:"You feel larger than life, optimistic, and ready to take on the world. Opportunities appear as if the universe is finally paying attention to your dreams.",advice:"Say yes to the big opportunity, but make sure your reach does not exceed your grasp. This is your green light, use it wisely.",duration:"About 2-3 weeks at peak, with effects felt over several months."},"Jupiter-Sun-opposition":{theme:"Others reflect your growth back to you, sometimes through excess or overcommitment.",feeling:"Relationships and partnerships bring expansion but also the temptation to overextend yourself trying to be everything to everyone.",advice:"Grow through collaboration but keep your own center. Not every opportunity that knocks deserves an answer.",duration:"About 2-3 weeks at peak, felt across a few months."},"Jupiter-Sun-square":{theme:"Restless growth that pushes against your current limits and comfort zone.",feeling:"An itchy dissatisfaction with the status quo, combined with an overwhelming number of possibilities pulling you in different directions.",advice:"Channel the restlessness into one meaningful expansion rather than scattering your energy across many. Quality over quantity.",duration:"About 2-3 weeks at peak, background energy for a few months."},"Jupiter-Moon-conjunction":{theme:"Emotional expansion, generosity of spirit, and a deepening of your inner life.",feeling:"Your heart feels bigger, your empathy is amplified, and you may experience a wave of emotional optimism that colors everything in warmer tones.",advice:"Let yourself feel the fullness of this emotional opening. It is a beautiful time to nurture yourself and strengthen your closest bonds.",duration:"About 1-2 weeks at peak, emotional effects linger for weeks."},"Jupiter-Venus-conjunction":{theme:"Love, pleasure, and abundance flow more easily into your life than usual.",feeling:"Everything feels more beautiful, more loving, and more generous. Romance blooms, friendships deepen, and your creative life sparkles with possibility.",advice:"Enjoy the abundance but watch for overindulgence. This is a wonderful time for love, art, and financial growth if you stay grounded.",duration:"About 1-2 weeks at peak, with a glow that lasts a few months."},"Saturn-Sun-conjunction":{theme:"A serious reality check on who you are and what you are building with your life.",feeling:"Heavy, mature, and stripped of illusions. You feel the weight of your responsibilities and the gap between who you are and who you want to be.",advice:"This is not punishment; it is a foundation-building period. Accept the limitations, do the hard work, and trust that what you build now will last decades.",duration:"About 2-3 weeks at peak, with a serious tone lasting several months."},"Saturn-Sun-opposition":{theme:"External pressures and authority figures challenge your sense of self and direction.",feeling:"You feel tested by life, bosses, institutions, or partners who demand more from you than feels fair. The pressure is real but so is the growth.",advice:"Meet the challenge with maturity rather than resentment. This is where you prove to yourself what you are made of.",duration:"About 2-3 weeks at peak, effects felt over several months."},"Saturn-Sun-square":{theme:"Friction between your ambitions and the structures constraining you.",feeling:"Frustration, self-doubt, and a sense that the world is not cooperating with your plans. Progress feels painfully slow.",advice:"Do not quit during this transit. The obstacles are teaching you discipline and patience. What survives this pressure is truly yours.",duration:"About 2-3 weeks at peak, building pressure felt for months."},"Saturn-Moon-conjunction":{theme:"Emotional maturity through confronting your deepest patterns and needs.",feeling:"Emotionally heavy, as if old grief and unmet needs are surfacing for review. Loneliness or emotional restriction may be prominent.",advice:"This is sacred emotional work. Face the feelings you have been avoiding. Therapy, journaling, or honest conversation can transform old wounds into wisdom.",duration:"About 2-3 weeks at peak, emotional weight lasting months."},"Saturn-Venus-conjunction":{theme:"A serious reckoning with your values, your relationships, and what love truly means to you.",feeling:"Love feels tested, finances feel tight, and you may question whether your current relationships are built on solid ground.",advice:"Relationships that survive this transit become unshakeable. Let go of what is not real, and invest deeply in what is.",duration:"About 2-3 weeks at peak, relationship themes active for months."},"Uranus-Sun-conjunction":{theme:"A radical awakening of your identity that breaks you free from outdated versions of yourself.",feeling:"Electric, restless, and unpredictable. You feel an urgent need to change something fundamental about your life, sometimes without knowing exactly what.",advice:"Honor the need for change but avoid burning everything down impulsively. The revolution is real; just make sure you are building something, not just destroying.",duration:"Peaks for a few weeks but the awakening unfolds over about a year."},"Uranus-Sun-opposition":{theme:"Others disrupt your sense of self, forcing you to reclaim your individuality.",feeling:"Sudden changes in relationships or external circumstances shake your identity loose from roles you have outgrown.",advice:"Let the disruption teach you who you really are underneath the compromises. This is liberation even when it feels like chaos.",duration:"Active for several weeks, with reverberations over about a year."},"Uranus-Moon-conjunction":{theme:"An emotional earthquake that frees you from patterns you did not know were holding you captive.",feeling:"Emotionally volatile, craving freedom, and suddenly unable to tolerate emotional situations you used to accept without question.",advice:"Your emotional truth is demanding expression. Create space for the new feelings without abandoning the people who matter.",duration:"Peaks for a few weeks, with emotional shifts unfolding over months."},"Uranus-Venus-conjunction":{theme:"A lightning bolt in your love life and values system that rewrites the rules of attraction.",feeling:"Sudden attractions, unexpected relationship changes, and a fierce need for romantic and financial freedom from the old patterns.",advice:"Stay open to unconventional love and unexpected beauty. The old formula for happiness is being upgraded whether you planned it or not.",duration:"Active for a few weeks at peak, love life shifts over about a year."},"Neptune-Sun-conjunction":{theme:"A dissolving of ego boundaries that opens you to spiritual depth and creative inspiration.",feeling:"Dreamy, confused, inspired, and uncertain all at once. Your sense of self becomes fluid, as if your edges are dissolving into something larger.",advice:"This is a deeply creative and spiritual time, but stay grounded in practical reality. Meditate, create art, and be cautious about major life decisions.",duration:"Peaks over a few weeks but the fog and inspiration lasts 1-2 years."},"Neptune-Moon-conjunction":{theme:"Your emotional boundaries dissolve, opening you to profound compassion and psychic sensitivity.",feeling:"Emotionally porous and deeply sensitive. You may cry more easily, feel others pain acutely, and experience vivid dreams and intuitive flashes.",advice:"Protect your emotional energy with clear boundaries while honoring your heightened sensitivity as a gift. Creative and healing work thrives now.",duration:"Active for several weeks at peak, with heightened sensitivity lasting over a year."},"Neptune-Venus-conjunction":{theme:"Love becomes transcendent, idealized, and beautifully confusing.",feeling:"A rose-tinted view of love that can produce soulmate connections or devastating illusions. Art and beauty feel like spiritual experiences.",advice:"Enjoy the romance and creative inspiration but do not make permanent commitments until the fog clears. Not everything that sparkles under this transit is real.",duration:"Peaks over a few weeks, with romantic and creative themes active for 1-2 years."},"Pluto-Sun-conjunction":{theme:"A total transformation of your identity through confrontation with your deepest power.",feeling:"Intense, volcanic, and unavoidable. Something within you is dying so that something more authentic can be born. Power dynamics become impossible to ignore.",advice:"Surrender to the transformation. The version of you that emerges will be more powerful, more honest, and more aligned with your true nature than anything before.",duration:"Peaks for a few weeks but the transformation unfolds over 1-3 years."},"Pluto-Moon-conjunction":{theme:"An emotional death and rebirth that transforms your relationship with vulnerability and intimacy.",feeling:"Emotionally raw and exposed. Old traumas surface, family dynamics intensify, and your emotional life undergoes a complete renovation from the foundation up.",advice:"This is the most powerful emotional healing transit you can experience. Get support, face the darkness, and trust that the emotional rebirth is worth the pain.",duration:"Peaks for a few weeks, with deep emotional work spanning 1-3 years."},"Pluto-Venus-conjunction":{theme:"Love and values are completely transformed through intensity, obsession, and eventual rebirth.",feeling:"Relationships become consuming, passionate, and confrontational. What you thought you wanted in love is being dismantled and rebuilt from the ground up.",advice:"Let the old patterns of love die. The relationships and values that emerge from this transit will be far more authentic and powerful than what came before.",duration:"Active for several weeks at peak, with relationship transformation spanning 1-2 years."}},k={Jupiter:"expansion and opportunity",Saturn:"discipline and restructuring",Uranus:"sudden change and liberation",Neptune:"dissolution and spiritual opening",Pluto:"deep transformation and empowerment"},S={Sun:"your core identity and life direction",Moon:"your emotional world and inner needs",Venus:"your love life, values, and sense of beauty",Mars:"your drive, ambition, and assertive energy",Mercury:"your mind, communication, and daily thinking",Jupiter:"your growth, faith, and sense of meaning",Saturn:"your structures, responsibilities, and long-term goals"},Y={Jupiter:{conjunction:"About 2-3 weeks at peak, effects over a few months.",opposition:"About 2-3 weeks at peak, effects over a few months.",trine:"About 1-2 weeks at peak.",square:"About 2-3 weeks at peak.",sextile:"About 1 week at peak."},Saturn:{conjunction:"About 2-3 weeks at peak, themes active for months.",opposition:"About 2-3 weeks at peak, themes active for months.",trine:"About 2 weeks at peak.",square:"About 2-3 weeks at peak, pressure building over months.",sextile:"About 1-2 weeks at peak."},Uranus:{conjunction:"Peaks for a few weeks, unfolds over about a year.",opposition:"Active for several weeks, reverberations over months.",trine:"About 2-3 weeks at peak.",square:"Peaks over weeks, disruption felt for months.",sextile:"About 2 weeks at peak."},Neptune:{conjunction:"Peaks over weeks, atmosphere lasts 1-2 years.",opposition:"Active for weeks, fog and clarity alternate over a year.",trine:"About 2-3 weeks at peak, inspiration lasts months.",square:"Peaks for weeks, confusion and growth span 1-2 years.",sextile:"About 2-3 weeks at peak."},Pluto:{conjunction:"Peaks for weeks, transformation spans 1-3 years.",opposition:"Active for weeks, power shifts unfold over 1-2 years.",trine:"About 3-4 weeks at peak, empowerment lasts months.",square:"Peaks for weeks, upheaval and rebirth span 1-3 years.",sextile:"About 2-3 weeks at peak."}};function x(e,t,n){return h[`${e}-${t}-${n}`]||null}function A(e,t,n){const o=h[`${e}-${t}-${n}`];if(o)return o;const i=k[e]||"planetary influence",a=S[t]||"this area of your life",s=n==="square"||n==="opposition",l=n==="trine"||n==="sextile",d=Y[e]?.[n]||"Duration varies based on planetary speed.";return{theme:`${e} brings ${i} to ${a} through a ${n}.`,feeling:s?`You may feel tension and pressure as ${e} challenges your natal ${t}, pushing you to grow through discomfort and honest reassessment.`:l?`A flowing, supportive energy as ${e} harmonizes with your natal ${t}, opening doors and easing your path forward.`:`An intense merging of ${e} energy with your natal ${t}, amplifying both the gifts and challenges of this combination.`,advice:s?`Work with the friction rather than against it. The pressure is creating something new and more authentic in the area of ${a}.`:l?`Take advantage of this harmonious window to make progress in ${a}. The energy supports growth with less resistance than usual.`:`Stay conscious of how this energy is reshaping ${a}. The changes happening now are significant and worth your full attention.`,duration:d}}const T=Object.freeze(Object.defineProperty({__proto__:null,getGenericTransitInterp:A,getTransitInterp:x},Symbol.toStringTag,{value:"Module"}));export{M as a,I as b,P as p,T as t};
